import React, { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import { fetchProductById } from "../services/api";

import { useShoppingCart } from "../contexts/CartContext";

import ReviewCard from '../components/ReviewCard';
import AddToCartModal from '../components/modals/AddToCartModal';

const ProductDetails = () => {
  const { id } = useParams();
  const [product, setProduct] = useState({});

  const loadData = async () => {
    try {
      const productData = await fetchProductById(id);
      setProduct(productData);
    } catch (err) {
      console.log("Ошибка при загрузке данных.");
    }
  };

  useEffect(() => {
    loadData();
  }, [id]);

  const { addItemToCart, isModalOpen, closePopup } = useShoppingCart();

  useEffect(() => {
    return () => {
      if (isModalOpen) {
        closePopup();
      }
    };
  }, [closePopup]);

  const reviews = product?.reviews || [];

  return (
    <div className="container mx-auto p-6 max-w-4xl">
      <AddToCartModal isOpen={isModalOpen} closePopup={closePopup} />
      <div className="bg-white shadow-lg rounded-lg p-6 flex flex-col md:flex-row gap-6">
        <img
          src={product.thumbnail}
          alt={product.title}
          className="w-full md:w-1/2 object-cover rounded-lg shadow-md"
        />
        <div className="flex flex-col justify-between md:w-1/2">
          <div>
            <h1 className="text-3xl font-bold text-gray-800">{product.title}</h1>
            <p className="text-lg text-gray-600 my-3">{product.description}</p>
            <p className="text-2xl font-semibold text-blue-600">${product.price}</p>
          </div>
          <button
            onClick={() => addItemToCart(product)}
            className="mt-4 px-6 py-3 bg-blue-500 text-white font-semibold rounded-lg shadow-md hover:bg-blue-700 transition-all">
            Add to cart
          </button>
        </div>
      </div>
      <div className="mt-8">
        <h2 className="text-2xl font-semibold text-gray-800">Customer Reviews</h2>
        <div className="mt-4 space-y-4">
          {reviews.length > 0 ? (
            reviews.map((review) => <ReviewCard key={review.id} review={review} />)
          ) : (
            <p className="text-gray-500">No reviews yet.</p>
          )}
        </div>
      </div>
    </div>
  );
};
export default ProductDetails;
